import Link from "next/link";
import { ReactNode } from "react";

type ButtonProps = {
  href?: string;
  children: ReactNode;
  className?: string;
  type?: "button" | "submit";
};

const baseClasses =
  "inline-flex items-center justify-center rounded-md bg-accent-500 px-5 py-3 text-sm font-semibold text-white transition hover:bg-accent-600 focus:outline-none focus-visible:ring-2 focus-visible:ring-accent-500 focus-visible:ring-offset-2";

export function Button({ href, children, className = "", type = "button" }: ButtonProps) {
  if (href) {
    return (
      <Link href={href} className={`${baseClasses} ${className}`.trim()}>
        {children}
      </Link>
    );
  }

  return (
    <button type={type} className={`${baseClasses} ${className}`.trim()}>
      {children}
    </button>
  );
}

